def calculate_final_price(order):
    if order['country_code'] == 'UK':
        vat_rate = 0.20
    elif order['country_code'] == 'DE':
        vat_rate = 0.19
    elif order['country_code'] == 'FR':
        vat_rate = 0.20
    else:
        vat_rate = 0.0 

    price_after_vat = order['subtotal'] * (1 + vat_rate)

    luxury_surcharge = 1.0
    for item in order['items']:
        if item['category'] == 'luxury':
            luxury_surcharge = 1.15
            break

    price_after_luxury = price_after_vat * luxury_surcharge

    final_price = price_after_luxury
    if order['subtotal'] > 100:
        final_price *= 0.95

    return round(final_price, 2)
